import React, { useState, useEffect } from "react";
import { Search, Loader } from "lucide-react";
import { fetchPaidSearchResults } from "../api";  

const PaidSearchTab = ({ token, query, setQuery, results, setResults, loading, setLoading }) => {
  // Add state for selected providers
  const [selectedProviders, setSelectedProviders] = React.useState(["tavily"]);
  const [searchMode, setSearchMode] = useState("live"); // "live" | "saved" | "both"
  const handleSearch = async () => {
    if (!query.trim()) return;
    setLoading(true);
    try {
      // Pass selectedProviders here
      const res = await fetchPaidSearchResults(token, query,selectedProviders);
      setResults(res);
    } catch (err) {
      alert("*****Failed to fetch paid search results.");
    }
    setLoading(false);
  };



  return (
    <div>
      <div className="flex gap-2 mb-4">
        <input
          type="text"
          value={query}
          placeholder="Enter search query..."
          onChange={(e) => setQuery(e.target.value)}
          className="flex-grow px-3 py-2 border rounded"
          onKeyDown={e => { if(e.key === 'Enter') handleSearch() }}
        />
        {/* Provider selector */}
        <select multiple
          value={selectedProviders}
          onChange={e => {
            const selected = Array.from(e.target.selectedOptions, option => option.value);
            setSelectedProviders(selected);
          }}
          className="border rounded px-2 py-1"
        >
          <option value="tavily">Tavily</option>
          {/* Add other providers as needed */}
        </select>
        <button
          onClick={handleSearch}
          disabled={loading}
          className="px-4 py-2 bg-blue-600 text-white rounded disabled:opacity-50 flex items-center gap-2"
        >
          {loading ? <Loader className="animate-spin w-4 h-4" /> : <Search className="w-4 h-4" />}
          Search
        </button>
      </div>

      {loading && <div>Loading...</div>}

      {!loading && results.length === 0 && (
        <div>No results found. Try another query.</div>
      )}

      {!loading && results.length > 0 && (
        <ul className="space-y-4">
          {results.map(article => (
            <li key={article.id || article.title} className="border p-4 rounded shadow-sm">
              <a
                href={article.meta_data?.link || article.link}
                target="_blank"
                rel="noopener noreferrer"
                className="font-semibold text-blue-600 hover:underline"
              >
                {article.title}
              </a>
              <p className="text-sm text-gray-700 mt-1">{article.summary}</p>
              <div className="mt-2 text-xs text-gray-500 flex gap-3">
                <span><strong>Source:</strong> {article.source || "Unknown"}</span>
                <span><strong>Score:</strong> {article.score}</span>
                {/* You can display more, like article.published, etc. */}
              </div>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default PaidSearchTab;
